/**
 * Generates desktop/src/buildFlags.ts from the build-time channel.
 *
 * TEST_TOOLS_ENABLED is ON only for the internal/test build (`npm run dist`,
 * which sets GROONE_TEST_TOOLS=1) and OFF for the customer build
 * (`npm run dist:prod`). Fail-safe OFF when GROONE_TEST_TOOLS is unset, so a
 * plain/forgotten build ships empty, never leaks test tooling.
 *
 * The generated file is gitignored — it is a build artifact, not source.
 */
const fs = require('fs');
const path = require('path');

const enabled = process.env.GROONE_TEST_TOOLS === '1';
const out = path.join(__dirname, '..', 'src', 'buildFlags.ts');

const content = `// AUTO-GENERATED by scripts/write-build-flags.js — do not edit.
// Build-time channel flag: ON for the internal/test build ('npm run dist'),
// OFF for the customer build ('npm run dist:prod'). Fail-safe OFF when unset.
export const TEST_TOOLS_ENABLED = ${enabled};
`;

fs.writeFileSync(out, content);
console.log(`[build-flags] TEST_TOOLS_ENABLED=${enabled}`);
